#define RECORD_SIZE 64
#define NUM_RECORDS 100

typedef struct {
    int id;
    char name[60];
} Record;

// Write record at specific position
void writeRecord(int fd, int recNum, Record *rec) {
    off_t offset = recNum * RECORD_SIZE;
    lseek(fd, offset, SEEK_SET);
    write(fd, rec, sizeof(Record));
}

// Read record at specific position (direct access)
void readRecord(int fd, int recNum, Record *rec) {
    off_t offset = recNum * RECORD_SIZE;
    lseek(fd, offset, SEEK_SET);
    read(fd, rec, sizeof(Record));
}

// Example usage:
// File address calculation: base + (record_number × RECORD_SIZE)

#define BLOCK_SIZE 512
#define INDEX_ENTRIES 100

// Index entry structure
typedef struct {
    int key;        // Primary key (e.g., employee ID)
    int block_addr; // Disk address of data block
} IndexEntry;

// Index file (in memory for this example)
IndexEntry index[INDEX_ENTRIES];
int index_count = 0;

// Build index from data file
void buildIndex(int data_fd) {
    int block_num = 0;
    Record rec;

    lseek(data_fd, 0, SEEK_SET);
    while (read(data_fd, &rec, sizeof(Record)) > 0) {
        index[index_count].key = rec.id;
        index[index_count].block_addr = block_num * BLOCK_SIZE;
        index_count++;
        block_num++;
    }
}

// Search using index
int indexedSearch(int data_fd, int searchKey) {
    // 1. Search index (could use binary search)
    for (int i = 0; i < index_count; i++) {
        if (index[i].key == searchKey) {
            // 2. Direct access to data block
            lseek(data_fd, index[i].block_addr, SEEK_SET);
            read(data_fd, &rec, sizeof(Record));
            return 1; // Found
        }
    }
    return 0; // Not found
}
